(function(){console.log(`PromptMemory: Auth Bridge Injected`);function e(){try{let e=null;for(let t=0;t<localStorage.length;t++){let n=localStorage.key(t);if(n&&n.startsWith(`sb-`)&&n.endsWith(`-auth-token`)){e=localStorage.getItem(n);break}}if(e){let t=JSON.parse(e);t&&t.access_token&&chrome.runtime.sendMessage({action:`SYNC_SESSION`,payload:t})}}catch(e){console.error(`PromptMemory: Error syncing session`,e)}}e(),window.addEventListener(`storage`,t=>{t.key&&t.key.startsWith(`sb-`)&&t.key.endsWith(`-auth-token`)&&e()}),setInterval(e,2e3);})()